export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

type CircuitStateName = "closed" | "open" | "half-open";

export interface CircuitState {
  failures: number;
  state: CircuitStateName;
  openedAt: number;
  halfOpenRequests: number;
}

export type CircuitStore = Map<string, CircuitState>;

export interface CircuitRequest {
  state: CircuitState;
  options: ResolvedCircuitBreakerOptions;
  isOuterRequest: boolean;
}

const defaults: ResolvedCircuitBreakerOptions = {
  threshold: 5,
  cooldown: 30_000,
  halfOpenMaxRequests: 1,
  failureStatusCodes: [408, 409, 425, 429, 500, 502, 503, 504],
};

export function resolveCircuitBreakerOptions(
  value: boolean | CircuitBreakerOptions | undefined
): ResolvedCircuitBreakerOptions | undefined {
  if (!value) {
    return;
  }
  return {
    ...defaults,
    ...(value === true ? {} : value),
  };
}

export function getRequestOrigin(request: RequestInfo): string | undefined {
  try {
    const url = request instanceof Request ? request.url : String(request);
    return new URL(url).origin;
  } catch {
    return;
  }
}

export function acquireCircuit(
  circuits: CircuitStore,
  origin: string,
  options: ResolvedCircuitBreakerOptions
): CircuitRequest {
  const state = circuits.get(origin) || {
    failures: 0,
    state: "closed" as const,
    openedAt: 0,
    halfOpenRequests: 0,
  };
  circuits.set(origin, state);

  if (state.state === "open") {
    if (Date.now() - state.openedAt < options.cooldown) {
      throw new Error("Circuit breaker is open");
    }
    state.state = "half-open";
    state.halfOpenRequests = 0;
  }

  if (state.state === "half-open") {
    if (state.halfOpenRequests >= options.halfOpenMaxRequests) {
      throw new Error("Circuit breaker is open");
    }
    state.halfOpenRequests++;
  }

  return { state, options, isOuterRequest: true };
}

export function finishCircuit(request: CircuitRequest, failed: boolean): void {
  const { state, options } = request;
  if (state.state === "half-open") {
    state.halfOpenRequests--;
  }

  if (failed) {
    state.failures++;
    if (state.state === "half-open" || state.failures >= options.threshold) {
      state.state = "open";
      state.openedAt = Date.now();
      state.halfOpenRequests = 0;
    }
    return;
  }

  state.failures = 0;
  if (state.state === "half-open") {
    state.state = "closed";
    state.halfOpenRequests = 0;
  }
